import json

def process_json(data: dict) -> str:
    """将字典序列化为格式化的JSON字符串"""
    return json.dumps(data, indent=2, ensure_ascii=False)

def parse_json(json_str: str) -> dict:
    """将JSON字符串反序列化为字典"""
    try:
        return json.loads(json_str)
    except json.JSONDecodeError as e:
        print(f"JSON解析错误: {e}")
        return {}

# 使用示例
if __name__ == "__main__":
    sample = {"key": "value", "number": 42}
    serialized = process_json(sample)
    print(serialized)
    deserialized = parse_json(serialized)
    print(deserialized)
